text.value:
{{(() => {
  let cellValue = input.cardData.triggerList;
  if (!cellValue || !cellValue.length) return '';

  const maxVisible = 1;
  const visible = cellValue.slice(0, maxVisible);
  const remaining = cellValue.slice(maxVisible);

  let html = `<div style="
    display:flex;
    align-items:center;
    gap:6px;
    flex-wrap:wrap;
    overflow:hidden;
    max-width:100%;
  ">`;

  // Render visible badges (first badge without ellipsis)
  visible.forEach(badge => {
    html += `<span title="${badge}" style="
      background:#DBEAFE;
      color:#1E40AF;
      padding:4px 10px;
      border-radius:999px;
      font-size:12px;
      font-weight:500;
      display:inline-block;
      /* removed ellipsis for first badge */
      white-space:nowrap;
       border:1px solid #BFDBFE;
    ">${badge}</span>`;
  });

  // Render +N badge (keep ellipsis for long text)
  if (remaining.length > 0) {
    const tooltipText = remaining.join(', ');

    html += `<span title="${tooltipText}" style="
      background:#DBEAFE;
      color:#1E40AF;
      padding:4px 8px;
      border-radius:999px;
      font-size:12px;
      font-weight:500;
      cursor:pointer;
      white-space:nowrap;
      max-width:100px;
      overflow:hidden;
      text-overflow:ellipsis;
      display:inline-block;
      border:1px solid #BFDBFE;
    ">+${remaining.length}</span>`;
  }

  html += `</div>`;

  return html;
})()}}

